-- Seed / upsert all blog_posts rows: the 3 original demo posts plus 18 new bilingual articles.
-- Safe to re-run any number of times: matches on slug and updates the row in place if it
-- already exists, inserts it if it does not.
--
-- Run this in the Supabase SQL editor for the AQAR FACTORY project -- the one whose blog_posts
-- table already has the title_ar / excerpt_ar / tags_ar / blocks_ar columns from the earlier
-- bilingual migration. Double-check you are in the right project before running.

insert into public.blog_posts
  (slug, title, title_ar, excerpt, excerpt_ar, cover, author_name, author_avatar, tags, tags_ar, blocks, blocks_ar, published_at, published)
values
  ('off-plan-buying-guide',
      'The Ultimate Guide to Buying Off-Plan Properties',
      'الدليل الشامل لشراء العقارات على الخريطة',
      'Off-plan can mean better pricing and flexible payment plans — but only if you know what to check before you sign. Here''s our advisors'' checklist.',
      'الشراء على الخريطة قد يعني أسعارًا أفضل وخطط سداد مرنة — لكن فقط إذا عرفت ما يجب التحقق منه قبل التوقيع. إليك قائمة مستشارينا.',
      '1600585154340-be6161a56a0c',
      'Sofia Marchetti',
      '1438761681033-6461ffad8d80',
      ARRAY['Off-plan', 'Buying guide', 'Investment']::text[],
      ARRAY['الشراء على الخريطة', 'دليل الشراء', 'استثمار']::text[],
      '[{"type":"paragraph","text":"Off-plan property — buying a home before it''s built — has become one of the fastest ways to enter a growth market at a lower price point. It also comes with real risk if you don''t know what to check first."},{"type":"heading","text":"Why buyers choose off-plan"},{"type":"paragraph","text":"Developers typically price off-plan units below projected completion value, and spread payments across the construction timeline instead of asking for the full amount up front. For buyers comfortable waiting two to four years, that gap between entry price and market value at handover is the whole appeal."},{"type":"image","image":"1600607687939-ce8a6c25118c"},{"type":"heading","text":"What to verify before you reserve a unit"},{"type":"paragraph","text":"Start with the developer''s track record: how many prior projects have they delivered, and were they on schedule? Ask for the escrow account details required by law in most markets — your payments should sit in a regulated account tied to construction milestones, not the developer''s general funds."},{"type":"paragraph","text":"Read the payment plan closely for what happens if handover slips. A good contract caps the delay penalty and gives you an exit if the project is delayed beyond a defined window."},{"type":"heading","text":"Our advisors'' rule of thumb"},{"type":"paragraph","text":"We only bring clients into off-plan developments from partners we''ve worked with before, with a public delivery history we can point to. If we haven''t seen a developer hand over a comparable project on time, we say so plainly before you commit a deposit."}]'::jsonb,
      '[{"type":"paragraph","text":"أصبح الشراء على الخريطة — أي اقتناء منزل قبل اكتمال بنائه — واحدًا من أسرع الطرق لدخول سوق نامٍ بسعر أقل. لكنه يحمل أيضًا مخاطر حقيقية إن لم تعرف ما الذي يجب التحقق منه أولاً."},{"type":"heading","text":"لماذا يختار المشترون الشراء على الخريطة"},{"type":"paragraph","text":"يسعّر المطورون عادةً الوحدات على الخريطة بأقل من قيمتها المتوقعة عند التسليم، ويوزعون الدفعات على مدار فترة البناء بدلاً من طلب المبلغ كاملاً مقدمًا. بالنسبة للمشترين الذين لا يمانعون الانتظار من سنتين إلى أربع سنوات، فإن الفارق بين سعر الدخول والقيمة السوقية عند التسليم هو جوهر الجاذبية."},{"type":"image","image":"1600607687939-ce8a6c25118c"},{"type":"heading","text":"ما الذي يجب التحقق منه قبل حجز وحدة"},{"type":"paragraph","text":"ابدأ بسجل المطوّر: كم مشروعًا سابقًا سلّمه، وهل التزم بالمواعيد؟ اطلب تفاصيل حساب الضمان (الإسكرو) الذي يفرضه القانون في معظم الأسواق — يجب أن تودَع مدفوعاتك في حساب منظم مرتبط بمراحل البناء، لا في حسابات المطوّر العامة."},{"type":"paragraph","text":"اقرأ خطة السداد بعناية لمعرفة ما يحدث في حال تأخر التسليم. العقد الجيد يحدد سقفًا لغرامة التأخير ويمنحك حق الانسحاب إذا تجاوز التأخير مدة محددة."},{"type":"heading","text":"قاعدة مستشارينا الذهبية"},{"type":"paragraph","text":"نُدخل عملاءنا فقط في مشاريع على الخريطة من شركاء تعاملنا معهم من قبل، ولديهم سجل تسليم علني يمكننا الإشارة إليه. وإذا لم نشهد مطوّرًا يسلّم مشروعًا مشابهًا في موعده، فإننا نقولها بوضوح قبل أن تلتزم بأي دفعة."}]'::jsonb,
      '2026-06-02T09:00:00.000Z',
      true),
  ('new-capital-investment-outlook',
      'New Capital: Why Investors Are Watching This City',
      'العاصمة الإدارية الجديدة: لماذا يراقبها المستثمرون؟',
      'Egypt''s New Administrative Capital has gone from government blueprint to one of the region''s most-discussed investment stories. Here''s what''s actually driving demand.',
      'تحوّلت العاصمة الإدارية الجديدة في مصر من مخطط حكومي إلى واحدة من أكثر قصص الاستثمار تداولًا في المنطقة. إليك ما يحرك الطلب فعليًا.',
      '1486406146926-c627a92ad1ab',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['Market insight', 'New Capital', 'Investment']::text[],
      ARRAY['رؤى السوق', 'العاصمة الإدارية الجديدة', 'استثمار']::text[],
      '[{"type":"paragraph","text":"A decade ago, the New Administrative Capital existed only on paper. Today it''s home to government ministries, a growing residential population, and a wave of developer activity that shows no sign of slowing."},{"type":"heading","text":"Infrastructure first"},{"type":"paragraph","text":"Unlike organic urban growth, New Capital was planned with roads, utilities and transit built ahead of demand rather than playing catch-up. That sequencing is a big part of why institutional developers moved in early — the hard infrastructure risk was already retired by the time private capital arrived."},{"type":"image","image":"1444723121867-7a241cacace9"},{"type":"heading","text":"What this means for buyers today"},{"type":"paragraph","text":"Early-phase pricing is largely gone, but the city is still years from being fully built out, which means the appreciation curve isn''t over. The projects worth watching now are the ones closest to completed amenities — schools, retail and the government district — rather than the cheapest plots furthest from them."},{"type":"paragraph","text":"As always, our advice is the same regardless of which city is trending: buy the unit and location you''d be glad to own even if the growth story slows, not just the one riding this month''s headlines."}]'::jsonb,
      '[{"type":"paragraph","text":"قبل عقد من الزمن، لم تكن العاصمة الإدارية الجديدة سوى مخطط على الورق. اليوم أصبحت موطنًا للوزارات الحكومية، وعدد سكاني متنامٍ، وموجة من نشاط المطورين لا تظهر أي علامة على التباطؤ."},{"type":"heading","text":"البنية التحتية أولاً"},{"type":"paragraph","text":"على عكس النمو العمراني العضوي، خُطط للعاصمة الإدارية الجديدة بإنشاء الطرق والمرافق ووسائل النقل قبل الطلب لا لمواكبته لاحقًا. هذا الترتيب هو جزء كبير من سبب دخول المطورين المؤسسيين مبكرًا — إذ كانت مخاطر البنية التحتية الصعبة قد انتهت بالفعل عند وصول رأس المال الخاص."},{"type":"image","image":"1444723121867-7a241cacace9"},{"type":"heading","text":"ماذا يعني هذا للمشترين اليوم"},{"type":"paragraph","text":"اختفت إلى حد كبير أسعار المراحل المبكرة، لكن المدينة ما زالت على بعد سنوات من الاكتمال، ما يعني أن منحنى ارتفاع الأسعار لم ينتهِ بعد. المشاريع الجديرة بالمتابعة الآن هي الأقرب إلى المرافق المكتملة — المدارس والمناطق التجارية والحي الحكومي — وليست فقط الأرخص والأبعد عنها."},{"type":"paragraph","text":"كما هو الحال دائمًا، نصيحتنا واحدة بغض النظر عن أي مدينة تشهد رواجًا: اشترِ الوحدة والموقع اللذين ستكون سعيدًا بامتلاكهما حتى لو تباطأت قصة النمو، لا فقط ما يتصدر عناوين هذا الشهر."}]'::jsonb,
      '2026-05-14T09:00:00.000Z',
      true),
  ('signs-time-to-upgrade-family-home',
      '5 Signs It''s Time to Upgrade Your Family Home',
      '5 علامات تدل على حاجتك لترقية منزل عائلتك',
      'Outgrowing a home rarely happens overnight — it creeps up. These are the signals our clients tell us they wish they''d acted on sooner.',
      'نادرًا ما يحدث تخطي حجم المنزل بين ليلة وضحاها — بل يتسلل تدريجيًا. هذه هي العلامات التي يخبرنا بها عملاؤنا أنهم تمنوا لو تصرفوا بشأنها في وقت أبكر.',
      '1560448204-e02f11c3d0e2',
      'Amara Okafor',
      '1494790108377-be9c29b29330',
      ARRAY['Home buying', 'Family', 'Lifestyle']::text[],
      ARRAY['شراء المنزل', 'العائلة', 'أسلوب الحياة']::text[],
      '[{"type":"paragraph","text":"Most families don''t wake up one day and decide to move — the decision builds slowly, room by room. Here are the signs we hear most often from clients right before they call us."},{"type":"heading","text":"1. Storage has become a daily negotiation"},{"type":"paragraph","text":"If getting the stroller out means moving three other things first, that''s not a storage problem you solve with organizers — it''s a space problem."},{"type":"heading","text":"2. Everyone works from the kitchen table"},{"type":"paragraph","text":"A home that had one clear \"quiet corner\" for remote work in 2021 often has three people needing one by now. If calls are getting scheduled around who''s home, it''s worth counting how many dedicated workspaces you actually need."},{"type":"image","image":"1449844908441-8829872d2607"},{"type":"heading","text":"3. You''ve stopped hosting"},{"type":"paragraph","text":"A quiet but reliable signal: families who once hosted regularly and gradually stopped, often because the space no longer comfortably fits the gathering they used to have."},{"type":"heading","text":"4. The commute math has changed"},{"type":"paragraph","text":"Whether it''s a new job, a new school, or a shift to hybrid work, a commute that made sense three years ago can quietly become the biggest source of weekly friction in the household."},{"type":"heading","text":"5. You''re renovating around problems instead of fixing them"},{"type":"paragraph","text":"If your last three home-improvement projects were about working around a layout rather than improving it, that budget might be better spent as a down payment on a home that already fits."}]'::jsonb,
      '[{"type":"paragraph","text":"لا تستيقظ معظم العائلات يومًا وتقرر الانتقال فجأة — بل يتشكل القرار تدريجيًا، غرفة تلو الأخرى. هذه هي العلامات التي نسمعها غالبًا من العملاء قبل أن يتصلوا بنا مباشرة."},{"type":"heading","text":"1. التخزين أصبح مفاوضة يومية"},{"type":"paragraph","text":"إذا كان إخراج عربة الطفل يستلزم نقل ثلاثة أشياء أخرى أولاً، فتلك ليست مشكلة تخزين تُحل بأدوات التنظيم — بل مشكلة مساحة."},{"type":"heading","text":"2. الجميع يعمل من طاولة المطبخ"},{"type":"paragraph","text":"المنزل الذي كان يحتوي على \"ركن هادئ\" واحد للعمل عن بُعد في 2021 غالبًا ما يحتاجه ثلاثة أشخاص الآن. إذا أصبحت المكالمات تُجدول حسب من يكون في المنزل، فمن المفيد حساب عدد مساحات العمل المخصصة التي تحتاجها فعليًا."},{"type":"image","image":"1449844908441-8829872d2607"},{"type":"heading","text":"3. توقفتم عن استضافة الضيوف"},{"type":"paragraph","text":"إشارة هادئة لكنها موثوقة: العائلات التي كانت تستضيف بانتظام ثم توقفت تدريجيًا، غالبًا لأن المساحة لم تعد تتسع بشكل مريح للتجمع الذي اعتادوا عليه."},{"type":"heading","text":"4. حسابات التنقل تغيّرت"},{"type":"paragraph","text":"سواء كانت وظيفة جديدة، أو مدرسة جديدة، أو تحول إلى العمل الهجين، فإن رحلة تنقل كانت منطقية قبل ثلاث سنوات يمكن أن تصبح بهدوء أكبر مصدر احتكاك أسبوعي في المنزل."},{"type":"heading","text":"5. تعيدون التجديد للتحايل على المشاكل بدلاً من حلها"},{"type":"paragraph","text":"إذا كانت مشاريع تحسين منزلك الثلاثة الأخيرة تدور حول التحايل على تصميم بدلاً من تحسينه، فقد يكون ذلك المال أفضل استثمارًا كدفعة مقدمة لمنزل يناسبكم بالفعل."}]'::jsonb,
      '2026-04-20T09:00:00.000Z',
      true),
  ('first-time-buyer-mortgage-guide-egypt',
      'A First-Time Buyer''s Guide to Mortgages in Egypt',
      'دليل المشتري لأول مرة للتمويل العقاري في مصر',
      'Bank mortgages and developer installment plans work very differently. Here''s how to tell which one actually fits your budget.',
      'التمويل العقاري البنكي وخطط التقسيط من المطوّر يعملان بطريقتين مختلفتين تمامًا. إليك كيف تعرف الأنسب لميزانيتك.',
      '1502005097973-6a7082348e28',
      'Karim Fahmy',
      '1463453091185-61582044d556',
      ARRAY['Mortgages', 'Financing', 'Buying guide']::text[],
      ARRAY['التمويل العقاري', 'التمويل', 'دليل الشراء']::text[],
      '[{"type":"paragraph","text":"Most first-time buyers in Egypt assume a mortgage works the same way a developer''s installment plan does. It doesn''t — and mixing the two up is the single most common financing mistake we see."},{"type":"heading","text":"Bank mortgage vs. developer installment plan"},{"type":"paragraph","text":"A bank mortgage is a loan: the bank pays the developer the full price up front, and you repay the bank in monthly installments that include interest, typically over 15 to 25 years, secured against the property itself. A developer installment plan is different — you''re paying the developer directly over the construction period (often 6 to 10 years), usually interest-free or with a modest markup baked into the price, and there''s no bank in the middle."},{"type":"heading","text":"What a bank actually looks at"},{"type":"paragraph","text":"Egyptian banks typically finance up to 80-90% of the property value for owner-occupiers, less for a second property or an investor purchase. They''ll want proof of stable income, a debt-to-income ratio that usually caps total monthly obligations around 35-40% of net income, and — critically — a registered title or a developer with a bank-approved project, since off-plan units without a clean title chain can be hard to mortgage until later phases."},{"type":"image","image":"1497366216548-37526070297c"},{"type":"heading","text":"When each option makes more sense"},{"type":"paragraph","text":"If you want to move in soon and the unit is already built or near handover, a mortgage lets you spread the cost over decades at a fixed monthly outlay. If you''re buying off-plan years before delivery, a developer''s own installment plan is usually cheaper overall, since you avoid bank interest entirely — the trade-off is that your money is exposed to the developer''s ability to deliver on schedule."},{"type":"paragraph","text":"Our advice to first-time buyers is simple: model both scenarios against your actual take-home income before you fall in love with a unit, not after. A payment plan that looks affordable on a glossy brochure can look very different once it''s the only line item competing with your rent, your car, and everything else."}]'::jsonb,
      '[{"type":"paragraph","text":"يفترض معظم المشترين لأول مرة في مصر أن التمويل العقاري البنكي يعمل بنفس طريقة خطة التقسيط من المطوّر. الأمر ليس كذلك — والخلط بين الاثنين هو الخطأ المالي الأكثر شيوعًا الذي نراه."},{"type":"heading","text":"التمويل العقاري البنكي مقابل خطة تقسيط المطوّر"},{"type":"paragraph","text":"التمويل العقاري البنكي هو قرض: يدفع البنك للمطوّر السعر كاملاً مقدمًا، وأنت تسدد للبنك أقساطًا شهرية تشمل فائدة، عادة على مدى 15 إلى 25 عامًا، مضمونة بالعقار نفسه. أما خطة تقسيط المطوّر فمختلفة — فأنت تدفع للمطوّر مباشرة على مدار فترة البناء (غالبًا من 6 إلى 10 سنوات)، عادة بدون فوائد أو بهامش بسيط مدمج في السعر، ولا يوجد بنك وسيط."},{"type":"heading","text":"ما الذي ينظر إليه البنك فعليًا"},{"type":"paragraph","text":"تموّل البنوك المصرية عادة حتى 80-90% من قيمة العقار للمشتري الذي سيسكن فيه، وأقل من ذلك للعقار الثاني أو الشراء الاستثماري. سيطلبون إثباتًا لدخل ثابت، ونسبة دين إلى دخل تحدّ عادة إجمالي الالتزامات الشهرية عند حوالي 35-40% من صافي الدخل، والأهم — سند ملكية مسجل أو مطوّر معتمد من البنك، إذ يصعب تمويل الوحدات على الخريطة دون سلسلة ملكية واضحة حتى مراحل لاحقة."},{"type":"image","image":"1497366216548-37526070297c"},{"type":"heading","text":"متى يكون كل خيار هو الأنسب"},{"type":"paragraph","text":"إذا كنت ترغب في الانتقال قريبًا والوحدة مكتملة أو قريبة من التسليم، يتيح لك التمويل العقاري توزيع التكلفة على عقود بمبلغ شهري ثابت. أما إذا كنت تشتري على الخريطة قبل سنوات من التسليم، فغالبًا ما تكون خطة تقسيط المطوّر أقل تكلفة إجمالاً لأنك تتجنب فوائد البنك تمامًا — والمقابل أن أموالك مرتبطة بقدرة المطوّر على الالتزام بالموعد."},{"type":"paragraph","text":"نصيحتنا للمشترين لأول مرة بسيطة: احسب السيناريوهين بناءً على صافي دخلك الفعلي قبل أن تقع في حب وحدة معينة، لا بعد ذلك. خطة الدفع التي تبدو ميسورة في كتيب أنيق قد تبدو مختلفة تمامًا عندما تصبح البند الوحيد الذي ينافس إيجارك وسيارتك وكل شيء آخر."}]'::jsonb,
      '2026-07-14T09:00:00.000Z',
      true),
  ('cash-vs-installments-payment-plan',
      'Cash vs. Installments: Which Payment Plan Actually Saves You Money?',
      'الدفع نقدًا أم بالتقسيط: أي خطة توفر لك أكثر؟',
      'Developers dangle a cash discount on one side and a multi-year installment plan on the other. The real answer depends on what your money can do elsewhere.',
      'يعرض المطوّرون خصم الدفع نقدًا من جهة وخطة تقسيط طويلة من جهة أخرى. الإجابة الحقيقية تعتمد على ما يمكن أن يفعله مالك في مكان آخر.',
      '1502005229762-cf1b2da7c5d6',
      'Karim Fahmy',
      '1463453091185-61582044d556',
      ARRAY['Financing', 'Investment', 'Buying guide']::text[],
      ARRAY['التمويل', 'استثمار', 'دليل الشراء']::text[],
      '[{"type":"paragraph","text":"Every price list in Egypt shows two numbers: the cash price and the installment price, and the gap between them — often 20-35% — is presented as a straightforward discount. It isn''t quite that simple."},{"type":"heading","text":"What the discount is really pricing in"},{"type":"paragraph","text":"That cash discount is the developer''s cost of capital: money today is worth more to them than the same amount spread over 6-8 years, especially with inflation eroding the real value of fixed EGP installments over time. From your side, the discount is only ''free money'' if you don''t have anywhere better to put that cash in the meantime."},{"type":"heading","text":"Run the actual comparison"},{"type":"paragraph","text":"Compare the cash discount rate against what your capital could realistically earn elsewhere — a savings certificate, a money market fund, or another investment — over the same period, adjusted for the fact that your installments are fixed in nominal EGP terms and effectively shrink in real terms if the pound weakens. In an inflationary environment, long installment plans on a fixed EGP schedule have quietly favored the buyer for the past few years, because you''re repaying with cheaper future currency."},{"type":"image","image":"1502005229762-cf1b2da7c5d6"},{"type":"heading","text":"It''s not purely financial"},{"type":"paragraph","text":"There''s a liquidity argument too: keeping capital in installments rather than locking it all into one asset gives you flexibility if an emergency or a better opportunity comes up. Conversely, a large cash payment can sometimes unlock a materially better unit or floor within the same project, since developers often reserve their best inventory for stronger offers."},{"type":"paragraph","text":"We walk clients through the actual numbers rather than the advertised discount percentage, because the right answer flips depending on your liquidity, your view on EGP inflation, and what else that cash could be doing for you."}]'::jsonb,
      '[{"type":"paragraph","text":"تعرض كل قائمة أسعار في مصر رقمين: سعر الكاش وسعر التقسيط، والفارق بينهما — غالبًا 20-35% — يُقدَّم كخصم مباشر. الأمر ليس بهذه البساطة تمامًا."},{"type":"heading","text":"ما الذي يسعّره الخصم فعليًا"},{"type":"paragraph","text":"خصم الكاش هو تكلفة رأس المال بالنسبة للمطوّر: المال اليوم يساوي له أكثر من نفس المبلغ موزعًا على 6-8 سنوات، خصوصًا مع تآكل التضخم للقيمة الحقيقية للأقساط الثابتة بالجنيه المصري بمرور الوقت. من جانبك، الخصم يكون \"مالاً مجانيًا\" فقط إذا لم يكن لديك مكان أفضل لوضع هذا المال فيه في هذه الأثناء."},{"type":"heading","text":"احسب المقارنة الفعلية"},{"type":"paragraph","text":"قارن نسبة خصم الكاش بما يمكن أن يحققه رأس مالك فعليًا في مكان آخر — شهادة ادخار، صندوق سوق نقدي، أو استثمار آخر — على نفس الفترة، مع الأخذ في الاعتبار أن أقساطك ثابتة بالجنيه الاسمي وتتقلص فعليًا إذا ضعف الجنيه. في بيئة تضخمية، كانت خطط التقسيط الطويلة بجدول ثابت بالجنيه تصب في مصلحة المشتري بهدوء خلال السنوات القليلة الماضية، لأنك تسدد بعملة مستقبلية أرخص."},{"type":"image","image":"1502005229762-cf1b2da7c5d6"},{"type":"heading","text":"الأمر ليس ماليًا بحتًا"},{"type":"paragraph","text":"هناك حجة السيولة أيضًا: الاحتفاظ برأس المال في أقساط بدلاً من حبسه بالكامل في أصل واحد يمنحك مرونة في حال ظهور طارئ أو فرصة أفضل. في المقابل، قد يفتح الدفع النقدي الكبير أحيانًا الباب لوحدة أو طابق أفضل بكثير ضمن نفس المشروع، لأن المطورين غالبًا ما يحتفظون بأفضل مخزونهم للعروض الأقوى."},{"type":"paragraph","text":"نستعرض مع عملائنا الأرقام الفعلية بدلاً من نسبة الخصم المعلنة، لأن الإجابة الصحيحة تتغير حسب سيولتك، ونظرتك لتضخم الجنيه، وما يمكن أن يحققه هذا المال في مكان آخر."}]'::jsonb,
      '2026-07-03T09:00:00.000Z',
      true),
  ('developer-contract-clauses-checklist',
      'Reading a Developer''s Contract: 10 Clauses You Should Never Skip',
      'قراءة عقد المطوّر: 10 بنود لا يجب تجاهلها أبدًا',
      'The unit you''re buying is only as good as the contract behind it. These are the clauses our legal team checks on every deal.',
      'الوحدة التي تشتريها لا تساوي أكثر من العقد الذي يقف خلفها. هذه هي البنود التي يتحقق منها فريقنا القانوني في كل صفقة.',
      '1497366216548-37526070297c',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['Buying guide', 'Legal', 'Off-plan']::text[],
      ARRAY['دليل الشراء', 'قانوني', 'الشراء على الخريطة']::text[],
      '[{"type":"paragraph","text":"A beautiful sales office and a friendly agent can''t tell you what actually happens if the project is delayed two years or the finish quality doesn''t match the model unit. The contract can — if you know where to look."},{"type":"heading","text":"The clauses that protect you"},{"type":"paragraph","text":"Delivery date and delay penalty: the contract should state a specific handover date, not a vague ''within the project timeline,'' plus a defined penalty (often a percentage of the unit value per month of delay) if the developer misses it. Unit specification schedule: finishes, brands, and fittings should be listed by name and grade, not described as ''high quality,'' since that phrase is unenforceable."},{"type":"heading","text":"The clauses that protect your money"},{"type":"paragraph","text":"Escrow or milestone-linked payments: your installments should be tied to construction progress and held in a regulated account, not paid straight into the developer''s general operating funds. Resale and assignment rights: confirm you can sell or transfer the unit before handover, and note any transfer fee the developer charges — some contracts restrict resale entirely during the payment period."},{"type":"image","image":"1441986300917-64674bd600d8"},{"type":"heading","text":"The clauses people skip and regret"},{"type":"paragraph","text":"Area tolerance: most contracts allow a small variance (commonly 2-5%) between the sold and as-built area with a pro-rated price adjustment — check the percentage and the direction it''s capped in. Force majeure definition: an overly broad force majeure clause can let a developer claim delays are excused for reasons that shouldn''t qualify, so read exactly what''s covered."},{"type":"paragraph","text":"None of these clauses are exotic — they''re standard in any well-run development. If a developer resists including them or hides behind boilerplate language, that response tells you as much as the contract itself."}]'::jsonb,
      '[{"type":"paragraph","text":"لا يمكن لمكتب مبيعات أنيق أو موظف ودود أن يخبرك بما سيحدث فعليًا إذا تأخر المشروع سنتين أو لم تطابق جودة التشطيب الوحدة النموذجية. العقد يستطيع ذلك — إذا عرفت أين تنظر."},{"type":"heading","text":"البنود التي تحميك"},{"type":"paragraph","text":"تاريخ التسليم وغرامة التأخير: يجب أن يحدد العقد تاريخ تسليم واضحًا، لا عبارة غامضة مثل \"ضمن الجدول الزمني للمشروع\"، بالإضافة إلى غرامة محددة (غالبًا نسبة من قيمة الوحدة عن كل شهر تأخير) إذا لم يلتزم المطوّر بها. جدول مواصفات الوحدة: يجب سرد التشطيبات والماركات والتجهيزات بالاسم والدرجة، لا وصفها بعبارة \"جودة عالية\" التي لا يمكن إثباتها قانونيًا."},{"type":"heading","text":"البنود التي تحمي أموالك"},{"type":"paragraph","text":"الدفعات المرتبطة بالإسكرو أو مراحل البناء: يجب أن ترتبط أقساطك بتقدم البناء وتُودَع في حساب منظم، لا تُدفع مباشرة إلى الحسابات التشغيلية العامة للمطوّر. حقوق إعادة البيع والتنازل: تأكد أنه يمكنك بيع أو نقل الوحدة قبل التسليم، ولاحظ أي رسوم تنازل يفرضها المطوّر — بعض العقود تمنع إعادة البيع تمامًا خلال فترة السداد."},{"type":"image","image":"1441986300917-64674bd600d8"},{"type":"heading","text":"البنود التي يتجاهلها الناس ثم يندمون"},{"type":"paragraph","text":"هامش تفاوت المساحة: تسمح معظم العقود بفارق صغير (عادة 2-5%) بين المساحة المباعة والمساحة الفعلية بعد البناء مع تعديل سعري نسبي — تحقق من النسبة والاتجاه الذي يحدها. تعريف القوة القاهرة: بند القوة القاهرة الفضفاض جدًا قد يسمح للمطوّر بتبرير التأخير لأسباب لا ينبغي أن تُحتسب، لذا اقرأ بالضبط ما الذي يغطيه."},{"type":"paragraph","text":"لا شيء من هذه البنود غريب — إنها معيار في أي مشروع يُدار بشكل جيد. إذا قاوم المطوّر إدراجها أو اختبأ خلف صياغة عامة، فإن ذلك الرد يخبرك بقدر ما يخبرك العقد نفسه."}]'::jsonb,
      '2026-06-22T09:00:00.000Z',
      true),
  ('ras-el-hekma-coastal-investment',
      'Ras El Hekma: Inside Egypt''s Biggest Coastal Investment Yet',
      'رأس الحكمة: داخل أكبر استثمار ساحلي في مصر حتى الآن',
      'The mega-deal context, the infrastructure timeline, and what buyers should watch for before committing to Egypt''s largest coastal development.',
      'سياق الصفقة الكبرى، والجدول الزمني للبنية التحتية، وما يجب أن ينتبه له المشترون قبل الالتزام بأكبر تطوير ساحلي في مصر.',
      '1524758631624-e2822e304c36',
      'Yasmin El-Sayed',
      '1517841905240-472988babdf9',
      ARRAY['Market insight', 'Ras El Hekma', 'North Coast']::text[],
      ARRAY['رؤى السوق', 'رأس الحكمة', 'الساحل الشمالي']::text[],
      '[{"type":"paragraph","text":"When Egypt announced the Ras El Hekma development deal, it wasn''t just another coastal project — it was the largest single foreign investment agreement in the country''s history, and it''s already reshaping how investors think about the North Coast."},{"type":"heading","text":"What''s actually being built"},{"type":"paragraph","text":"The masterplan covers a vast stretch of Mediterranean coastline west of Alamein, with plans for residential districts, a financial free zone, resorts, a marina, and an international airport upgrade — effectively a new city rather than a seasonal summer destination. That distinction matters: North Coast projects have historically been vacation-only compounds; Ras El Hekma is being planned with year-round infrastructure."},{"type":"heading","text":"The infrastructure timeline"},{"type":"paragraph","text":"Large-scale phased developments like this typically deliver core infrastructure — roads, utilities, the airport expansion — well ahead of most residential handovers, which is both the opportunity and the risk: entry pricing today reflects a project still under construction, but the full amenity and connectivity picture won''t be clear for several years."},{"type":"image","image":"1524758631624-e2822e304c36"},{"type":"heading","text":"What buyers should watch for"},{"type":"paragraph","text":"Ask specifically which phase and sub-zone a unit sits in, since pricing and delivery timelines vary significantly across a masterplan this size. Verify which infrastructure commitments are already funded and contracted versus still at the planning stage, and treat any ''guaranteed rental yield'' marketing claim with the same scrutiny you''d apply anywhere else."},{"type":"paragraph","text":"Ras El Hekma is a genuinely different scale of project for Egypt''s coast, and that''s exactly why it deserves more diligence, not less, before you commit — the size of the headline shouldn''t substitute for checking the specifics of your unit."}]'::jsonb,
      '[{"type":"paragraph","text":"عندما أعلنت مصر عن اتفاقية تطوير رأس الحكمة، لم يكن الأمر مجرد مشروع ساحلي آخر — بل كان أكبر اتفاقية استثمار أجنبي مباشر في تاريخ البلاد، وهو يعيد بالفعل تشكيل نظرة المستثمرين للساحل الشمالي."},{"type":"heading","text":"ما الذي يُبنى فعليًا"},{"type":"paragraph","text":"يغطي المخطط الرئيسي امتدادًا واسعًا من ساحل البحر المتوسط غرب العلمين، مع خطط لأحياء سكنية، ومنطقة حرة مالية، ومنتجعات، ومارينا، وتطوير مطار دولي — أي مدينة جديدة فعليًا وليس مجرد وجهة صيفية موسمية. هذا الفارق مهم: كانت مشاريع الساحل الشمالي تاريخيًا مجمعات للإجازات فقط؛ أما رأس الحكمة فيُخطط له ببنية تحتية تعمل طوال العام."},{"type":"heading","text":"الجدول الزمني للبنية التحتية"},{"type":"paragraph","text":"عادة ما تُسلَّم المشاريع الكبرى المرحلية مثل هذا البنية التحتية الأساسية — الطرق والمرافق وتوسعة المطار — قبل معظم تسليمات الوحدات السكنية بوقت طويل، وهو ما يمثل الفرصة والمخاطرة معًا: أسعار الدخول اليوم تعكس مشروعًا لا يزال قيد الإنشاء، لكن الصورة الكاملة للمرافق والربط لن تتضح إلا بعد عدة سنوات."},{"type":"image","image":"1524758631624-e2822e304c36"},{"type":"heading","text":"ما الذي يجب أن ينتبه له المشترون"},{"type":"paragraph","text":"اسأل تحديدًا عن المرحلة والمنطقة الفرعية التي تقع فيها الوحدة، لأن الأسعار وجداول التسليم تختلف بشكل كبير عبر مخطط بهذا الحجم. تحقق من التزامات البنية التحتية الممولة والمتعاقد عليها فعليًا مقابل ما لا يزال في مرحلة التخطيط، وتعامل مع أي ادعاء تسويقي بـ\"عائد إيجار مضمون\" بنفس الحذر الذي تطبقه في أي مكان آخر."},{"type":"paragraph","text":"رأس الحكمة مشروع بحجم مختلف فعليًا لساحل مصر، وهذا بالضبط سبب استحقاقه عناية أكبر لا أقل قبل الالتزام — فحجم العنوان الإعلامي لا يجب أن يحل محل التحقق من تفاصيل وحدتك."}]'::jsonb,
      '2026-06-11T09:00:00.000Z',
      true),
  ('fifth-settlement-vs-new-capital',
      '5th Settlement vs. New Capital: Which Should You Buy Into in 2026?',
      'التجمع الخامس أم العاصمة الإدارية الجديدة: أين تستثمر في 2026؟',
      'Side by side: price per meter, amenity completion status, and resale liquidity across Cairo''s two most-discussed eastern hubs.',
      'مقارنة جنبًا إلى جنب: سعر المتر، وحالة اكتمال المرافق، وسيولة إعادة البيع بين أكثر منطقتين شرقيتين تداولًا في القاهرة.',
      '1502672260266-1c1ef2d93688',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['Market insight', 'New Capital', '5th Settlement']::text[],
      ARRAY['رؤى السوق', 'العاصمة الإدارية الجديدة', 'التجمع الخامس']::text[],
      '[{"type":"paragraph","text":"Both areas sit within a short drive of each other on Cairo''s eastern edge, and both get pitched as ''the'' place to buy right now. In practice, they serve different buyers for different reasons."},{"type":"heading","text":"Price per meter and what it buys"},{"type":"paragraph","text":"5th Settlement commands a premium over New Capital largely because it''s established: mature landscaping, operating schools, functioning retail, and a resale market with real transaction history. New Capital''s per-meter pricing is generally lower, but a meaningful share of what you''re buying is still being built around you."},{"type":"heading","text":"Amenity completion status"},{"type":"paragraph","text":"In 5th Settlement, most of what you see marketed already exists and is in daily use. In New Capital, government relocation and the downtown business district are advancing steadily, but full retail and lifestyle build-out across every district is still a multi-year process — worth confirming against your specific compound rather than the city as a whole."},{"type":"image","image":"1502672260266-1c1ef2d93688"},{"type":"heading","text":"Resale liquidity"},{"type":"paragraph","text":"5th Settlement has the deeper resale market today simply because more units have changed hands there over more years, which matters if you might need to sell rather than hold to term. New Capital''s resale market is thinner but growing, and buyers willing to accept that illiquidity in the near term are effectively being compensated for it through lower entry pricing."},{"type":"paragraph","text":"Neither is the objectively ''better'' answer — 5th Settlement suits buyers who want a finished lifestyle today, New Capital suits buyers comfortable trading a few years of patience for a lower entry price and exposure to the country''s next major growth story."}]'::jsonb,
      '[{"type":"paragraph","text":"تقع كلتا المنطقتين على مسافة قريبة من بعضهما على الحافة الشرقية للقاهرة، ويُروَّج لكل منهما بأنها \"المكان\" الأمثل للشراء الآن. عمليًا، تخدم كل منطقة نوعًا مختلفًا من المشترين لأسباب مختلفة."},{"type":"heading","text":"سعر المتر وما الذي تحصل عليه مقابله"},{"type":"paragraph","text":"يحمل التجمع الخامس علاوة سعرية عن العاصمة الإدارية الجديدة لأنه منطقة راسخة إلى حد كبير: مسطحات خضراء ناضجة، مدارس فعّالة، تجزئة تعمل، وسوق إعادة بيع بتاريخ معاملات حقيقي. أسعار المتر في العاصمة الإدارية أقل عمومًا، لكن جزءًا كبيرًا مما تشتريه لا يزال قيد الإنشاء حولك."},{"type":"heading","text":"حالة اكتمال المرافق"},{"type":"paragraph","text":"في التجمع الخامس، معظم ما يُسوَّق موجود بالفعل ويُستخدم يوميًا. في العاصمة الإدارية، يتقدم انتقال الحكومة والحي المركزي للأعمال بثبات، لكن الاكتمال الكامل للتجزئة ونمط الحياة في كل حي لا يزال عملية تستغرق عدة سنوات — يستحق التحقق منها بحسب الكمبوند المحدد لا المدينة ككل."},{"type":"image","image":"1502672260266-1c1ef2d93688"},{"type":"heading","text":"سيولة إعادة البيع"},{"type":"paragraph","text":"يمتلك التجمع الخامس سوق إعادة بيع أعمق اليوم لمجرد أن وحدات أكثر انتقلت ملكيتها هناك على مدى سنوات أطول، وهو أمر مهم إذا احتجت للبيع بدلاً من الاحتفاظ حتى نهاية المدة. سوق إعادة البيع في العاصمة الإدارية أضعف لكنه ينمو، والمشترون المستعدون لقبول ضعف السيولة هذا في المدى القريب يحصلون فعليًا على تعويض عنه من خلال سعر دخول أقل."},{"type":"paragraph","text":"لا توجد إجابة \"أفضل\" موضوعيًا — التجمع الخامس يناسب من يريد نمط حياة مكتملًا اليوم، والعاصمة الإدارية تناسب من يقبل مقايضة بضع سنوات من الصبر بسعر دخول أقل وحصة في قصة النمو الكبرى القادمة للبلاد."}]'::jsonb,
      '2026-05-31T09:00:00.000Z',
      true),
  ('al-shrouk-quiet-rise',
      'Al Shrouk''s Quiet Rise: Why It''s Becoming East Cairo''s Sleeper Hit',
      'الصعود الهادئ للشروق: لماذا أصبحت الأفضل شرق القاهرة؟',
      'Ring-road and airport proximity, and a price trajectory that''s been climbing quietly while New Capital and 5th Settlement take the headlines.',
      'قرب الطريق الدائري والمطار، ومسار أسعار يتصاعد بهدوء بينما تستحوذ العاصمة الإدارية والتجمع الخامس على العناوين.',
      '1505691938895-1758d7feb511',
      'Yasmin El-Sayed',
      '1517841905240-472988babdf9',
      ARRAY['Market insight', 'Al Shrouk', 'New Cairo']::text[],
      ARRAY['رؤى السوق', 'الشروق', 'القاهرة الجديدة']::text[],
      '[{"type":"paragraph","text":"While New Capital and 5th Settlement dominate the headlines, Al Shrouk has spent the past few years quietly building one of East Cairo''s steadiest price trajectories — without the marketing noise."},{"type":"heading","text":"The location advantage"},{"type":"paragraph","text":"Al Shrouk sits directly along the Cairo-Suez road with fast access to the ring road and Cairo Airport, a combination that matters more to daily commuters than any single amenity list. That connectivity is largely why the area has attracted steady, organic demand rather than purely investor-driven buying."},{"type":"heading","text":"How pricing compares"},{"type":"paragraph","text":"Per-meter pricing in Al Shrouk generally sits below its immediate New Cairo neighbors while offering comparable build quality and unit sizes, largely because it hasn''t attracted the same marketing spend as newer, more heavily promoted developments nearby."},{"type":"image","image":"1505691938895-1758d7feb511"},{"type":"heading","text":"What''s changing now"},{"type":"paragraph","text":"A wave of newer compounds has moved in over the past two years, bringing updated amenities and design standards without erasing the area''s relative value gap — for now. That gap has been narrowing steadily as more buyers discover the area, which is usually the sign an early-mover advantage is starting to close."},{"type":"paragraph","text":"We''ve been placing more clients in Al Shrouk specifically because it rewards patience without asking you to bet on a masterplan that''s still years from completion — it''s already a functioning, connected part of East Cairo today."}]'::jsonb,
      '[{"type":"paragraph","text":"بينما تهيمن العاصمة الإدارية والتجمع الخامس على عناوين الأخبار، قضت الشروق السنوات القليلة الماضية في بناء واحد من أكثر مسارات الأسعار ثباتًا شرق القاهرة بهدوء — دون ضجيج تسويقي."},{"type":"heading","text":"ميزة الموقع"},{"type":"paragraph","text":"تقع الشروق مباشرة على طريق القاهرة السويس مع وصول سريع للطريق الدائري ومطار القاهرة، وهذا المزيج مهم للمتنقلين يوميًا أكثر من أي قائمة مرافق منفردة. هذا الترابط هو السبب الرئيسي في جذب المنطقة لطلب ثابت وعضوي بدلاً من شراء يقوده المستثمرون فقط."},{"type":"heading","text":"كيف تقارن الأسعار"},{"type":"paragraph","text":"أسعار المتر في الشروق أقل عمومًا من جاراتها المباشرة في القاهرة الجديدة مع تقديم جودة بناء وأحجام وحدات مماثلة، ويعود ذلك إلى حد كبير لعدم جذبها نفس الإنفاق التسويقي الذي تحظى به المشاريع الأحدث والأكثر ترويجًا القريبة منها."},{"type":"image","image":"1505691938895-1758d7feb511"},{"type":"heading","text":"ما الذي يتغير الآن"},{"type":"paragraph","text":"دخلت موجة من الكمبوندات الأحدث خلال العامين الماضيين، حاملة مرافق ومعايير تصميم محدّثة دون أن تمحو فجوة القيمة النسبية للمنطقة — حتى الآن. ظلت هذه الفجوة تضيق بثبات مع اكتشاف المزيد من المشترين للمنطقة، وهو عادة إشارة إلى بدء انغلاق ميزة الداخل المبكر."},{"type":"paragraph","text":"نضع المزيد من عملائنا في الشروق تحديدًا لأنها تكافئ الصبر دون أن تطلب منك المراهنة على مخطط رئيسي لا يزال على بعد سنوات من الاكتمال — إنها بالفعل جزء فعّال ومترابط من شرق القاهرة اليوم."}]'::jsonb,
      '2026-05-20T09:00:00.000Z',
      true),
  ('new-capital-two-years-progress-report',
      'Egypt''s New Administrative Capital, Two Years In: A Progress Report',
      'العاصمة الإدارية الجديدة بعد عامين: تقرير حالة',
      'What''s actually been delivered — government relocation, the monorail, the first retail — versus what''s still catching up.',
      'ما الذي تم إنجازه فعليًا — انتقال الحكومة، والمونوريل، وأولى المشاريع التجارية — مقابل ما لا يزال يلحق بالركب.',
      '1567496898669-ee935f5f647a',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['New Capital', 'Market insight', 'Infrastructure']::text[],
      ARRAY['العاصمة الإدارية الجديدة', 'رؤى السوق', 'البنية التحتية']::text[],
      '[{"type":"paragraph","text":"Two years after the first ministries relocated, New Capital has moved from ''promised city'' to a place with a genuine, if partial, daily life. Here''s an honest accounting of what''s delivered and what isn''t."},{"type":"heading","text":"What''s actually operating"},{"type":"paragraph","text":"The government district is functioning, with core ministries relocated and staff commuting daily. The monorail line connecting New Capital to greater Cairo is operational, cutting a commute that used to demand a car into a fixed-schedule ride. The first large retail and entertainment developments are open and drawing weekend traffic from across the city, not just residents."},{"type":"heading","text":"What''s still catching up"},{"type":"paragraph","text":"Retail and services density still varies enormously by district — some neighborhoods have a full supermarket and clinic within walking distance, others are still waiting on their first. School capacity has expanded but hasn''t fully caught up with the pace of residential handovers, which is worth checking street-by-street rather than assuming citywide."},{"type":"image","image":"1567496898669-ee935f5f647a"},{"type":"heading","text":"What this means for the next wave of buyers"},{"type":"paragraph","text":"The ''is this city real'' question that dominated conversations three years ago has largely been settled — the practical question now is which specific district and phase you''re buying into, since the gap between the most-developed and least-developed pockets of New Capital is still wide."},{"type":"paragraph","text":"We tell clients to visit the specific district on a weekday, not just the sales gallery, before committing — the city as a whole has clearly arrived, but ''New Capital'' now covers a wide range of lived experiences depending on exactly where you land."}]'::jsonb,
      '[{"type":"paragraph","text":"بعد عامين من انتقال أولى الوزارات، تحوّلت العاصمة الإدارية الجديدة من \"مدينة موعودة\" إلى مكان بحياة يومية حقيقية، وإن كانت جزئية. إليك محاسبة صادقة لما تم إنجازه وما لم يُنجز بعد."},{"type":"heading","text":"ما الذي يعمل فعليًا"},{"type":"paragraph","text":"الحي الحكومي يعمل، مع انتقال الوزارات الأساسية وتنقل الموظفين يوميًا. خط المونوريل الذي يربط العاصمة الإدارية بالقاهرة الكبرى يعمل بالفعل، محولاً تنقلاً كان يتطلب سيارة إلى رحلة بجدول ثابت. أُفتتحت أولى المشاريع التجارية والترفيهية الكبرى وتجذب حركة نهاية الأسبوع من أنحاء المدينة، لا من السكان فقط."},{"type":"heading","text":"ما الذي لا يزال يلحق بالركب"},{"type":"paragraph","text":"لا تزال كثافة التجزئة والخدمات تتفاوت بشكل كبير حسب الحي — بعض الأحياء لديها سوبر ماركت وعيادة كاملة على مسافة سير، وأخرى لا تزال تنتظر أولاها. توسعت الطاقة الاستيعابية للمدارس لكنها لم تواكب بالكامل وتيرة تسليم الوحدات السكنية، وهو ما يستحق التحقق منه شارعًا بشارع لا بافتراض شمول المدينة كلها."},{"type":"image","image":"1567496898669-ee935f5f647a"},{"type":"heading","text":"ماذا يعني هذا للموجة القادمة من المشترين"},{"type":"paragraph","text":"سؤال \"هل هذه المدينة حقيقية\" الذي هيمن على النقاشات قبل ثلاث سنوات قد حُسم إلى حد كبير — السؤال العملي الآن هو أي حي ومرحلة محددة تشتري فيها، إذ لا تزال الفجوة بين أكثر مناطق العاصمة الإدارية تطورًا وأقلها تطورًا واسعة."},{"type":"paragraph","text":"ننصح عملاءنا بزيارة الحي المحدد في يوم عمل عادي، لا صالة المبيعات فقط، قبل الالتزام — فالمدينة ككل وصلت بوضوح، لكن \"العاصمة الإدارية\" تغطي الآن نطاقًا واسعًا من التجارب المعيشية حسب مكانك بالضبط."}]'::jsonb,
      '2026-05-09T09:00:00.000Z',
      true),
  ('rental-yields-vs-capital-appreciation',
      'Rental Yields vs. Capital Appreciation: How to Think Like a Real Estate Investor',
      'عائد الإيجار أم نمو رأس المال: كيف يفكر المستثمر العقاري الذكي؟',
      'A framework for evaluating a property''s investment performance, whether you''re buying to rent or buying to resell.',
      'إطار عمل لتقييم الأداء الاستثماري للعقار، سواء كنت تشتري للتأجير أو لإعادة البيع.',
      '1497366811353-6870744d04b2',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['Investment', 'Market insight']::text[],
      ARRAY['استثمار', 'رؤى السوق']::text[],
      '[{"type":"paragraph","text":"Ask ten property investors what makes a good investment and you''ll get ten different answers, but most of them collapse into a single trade-off: income now versus growth later."},{"type":"heading","text":"Two different games"},{"type":"paragraph","text":"Rental yield measures the annual income a property generates as a percentage of its price — a steady, relatively predictable cash return you can measure from day one. Capital appreciation is the change in the property''s value over time, which is far less predictable but has historically been where the larger gains in fast-growing markets actually come from."},{"type":"heading","text":"Why Egypt has leaned toward appreciation"},{"type":"paragraph","text":"In a market where new cities and infrastructure are being built from the ground up, and where currency dynamics have made EGP-denominated assets attractive to hold, the bigger returns for most of our clients over the past several years have come from buying early in a growth corridor and holding through delivery, not from rental income along the way."},{"type":"image","image":"1497366811353-6870744d04b2"},{"type":"heading","text":"How to think about your own mix"},{"type":"paragraph","text":"If you need the property to generate income you can use now, weight your search toward established areas with existing rental demand and realistic occupancy. If you''re investing capital you don''t need to touch for years, an earlier-stage growth corridor with a longer appreciation runway may outperform, even with weaker rental yield in the meantime."},{"type":"paragraph","text":"The mistake we see most often isn''t choosing the wrong strategy — it''s not choosing one at all, and ending up with a property that''s mediocre at both."}]'::jsonb,
      '[{"type":"paragraph","text":"اسأل عشرة مستثمرين عقاريين عمّا يجعل الاستثمار جيدًا وستحصل على عشر إجابات مختلفة، لكن معظمها يختصر في مقايضة واحدة: دخل الآن مقابل نمو لاحقًا."},{"type":"heading","text":"لعبتان مختلفتان"},{"type":"paragraph","text":"عائد الإيجار يقيس الدخل السنوي الذي يولّده العقار كنسبة من سعره — عائد نقدي ثابت وقابل للتنبؤ نسبيًا يمكنك قياسه من اليوم الأول. أما نمو رأس المال فهو التغير في قيمة العقار بمرور الوقت، وهو أقل قابلية للتنبؤ بكثير لكنه تاريخيًا مصدر المكاسب الأكبر فعليًا في الأسواق سريعة النمو."},{"type":"heading","text":"لماذا مالت مصر نحو نمو رأس المال"},{"type":"paragraph","text":"في سوق تُبنى فيه مدن وبنية تحتية جديدة من الصفر، وحيث جعلت ديناميكيات العملة الأصول المقومة بالجنيه المصري جذابة للاحتفاظ بها، جاءت العوائد الأكبر لمعظم عملائنا خلال السنوات القليلة الماضية من الشراء المبكر في ممر نمو والاحتفاظ حتى التسليم، لا من دخل الإيجار على طول الطريق."},{"type":"image","image":"1497366811353-6870744d04b2"},{"type":"heading","text":"كيف تفكر في مزيجك الخاص"},{"type":"paragraph","text":"إذا كنت تحتاج للعقار أن يولّد دخلاً يمكنك استخدامه الآن، وجّه بحثك نحو مناطق راسخة بطلب إيجاري قائم وإشغال واقعي. أما إذا كنت تستثمر رأس مالاً لا تحتاج لمسّه لسنوات، فقد يتفوق ممر نمو في مرحلة مبكرة بمدى نمو أطول، حتى مع عائد إيجاري أضعف في الأثناء."},{"type":"paragraph","text":"الخطأ الذي نراه غالبًا ليس اختيار الاستراتيجية الخاطئة — بل عدم اختيار أي استراتيجية على الإطلاق، وينتهي الأمر بعقار متوسط في كلا الجانبين."}]'::jsonb,
      '2026-04-28T09:00:00.000Z',
      true),
  ('currency-devaluation-property-market',
      'How Currency Devaluation Has Reshaped Egypt''s Property Market',
      'كيف أعاد تعويم الجنيه تشكيل سوق العقارات في مصر؟',
      'EGP volatility has pushed pricing toward dollar-linked models and made property one of the most trusted stores of value. Here''s what it means for buyers.',
      'دفع تقلب الجنيه التسعير نحو نماذج مرتبطة بالدولار وجعل العقار أحد أكثر مخازن القيمة موثوقية. إليك ماذا يعني ذلك للمشترين.',
      '1493809842364-78817add7ffb',
      'Karim Fahmy',
      '1463453091185-61582044d556',
      ARRAY['Market insight', 'Financing', 'Investment']::text[],
      ARRAY['رؤى السوق', 'التمويل', 'استثمار']::text[],
      '[{"type":"paragraph","text":"The pound''s devaluation over the past several years didn''t just move a number on an exchange rate screen — it rewired how real estate gets priced, financed, and sold across Egypt."},{"type":"heading","text":"The shift toward dollar-linked pricing"},{"type":"paragraph","text":"Many developers now price units with reference to USD, either directly or through periodic EGP repricing tied to the exchange rate, specifically to protect their own construction costs, which include a meaningful share of imported materials and equipment. For buyers, that means the ''price'' quoted today may not be the price you actually pay across a multi-year installment plan."},{"type":"heading","text":"Why EGP assets became more attractive to hold"},{"type":"paragraph","text":"For Egyptians holding EGP savings, real estate has functioned as one of the more effective ways to preserve value against inflation, since property prices have broadly tracked or outpaced the currency''s depreciation over time — unlike cash sitting in a low-yield account. That dynamic has pulled buyers into the market who were previously sitting on the sidelines."},{"type":"image","image":"1493809842364-78817add7ffb"},{"type":"heading","text":"What to check before you commit"},{"type":"paragraph","text":"Ask explicitly whether your payment plan is fixed in EGP for its full term or subject to repricing, and if so, on what basis and how often. A plan that looks affordable today can move meaningfully if it''s indexed to a rate that shifts before your final installment."},{"type":"paragraph","text":"None of this means avoid the market — it means read your specific contract''s currency terms as carefully as its delivery date, because that clause quietly determines what you''ll actually end up paying."}]'::jsonb,
      '[{"type":"paragraph","text":"لم يقتصر تعويم الجنيه المصري خلال السنوات القليلة الماضية على تحريك رقم على شاشة سعر الصرف — بل أعاد تشكيل طريقة تسعير العقارات وتمويلها وبيعها في مصر بالكامل."},{"type":"heading","text":"التحول نحو التسعير المرتبط بالدولار"},{"type":"paragraph","text":"يسعّر كثير من المطورين الآن الوحدات بالإشارة إلى الدولار الأمريكي، إما مباشرة أو من خلال إعادة تسعير دورية بالجنيه مرتبطة بسعر الصرف، وذلك تحديدًا لحماية تكاليف البناء الخاصة بهم التي تتضمن حصة كبيرة من المواد والمعدات المستوردة. بالنسبة للمشترين، هذا يعني أن \"السعر\" المعلن اليوم قد لا يكون السعر الذي تدفعه فعليًا عبر خطة تقسيط متعددة السنوات."},{"type":"heading","text":"لماذا أصبحت الأصول بالجنيه أكثر جاذبية للاحتفاظ بها"},{"type":"paragraph","text":"بالنسبة للمصريين الذين يحتفظون بمدخرات بالجنيه، عمل العقار كأحد أكثر الطرق فعالية للحفاظ على القيمة أمام التضخم، إذ واكبت أسعار العقارات بشكل عام انخفاض قيمة العملة أو تفوقت عليه بمرور الوقت — على عكس النقد في حساب منخفض العائد. هذه الديناميكية جذبت مشترين كانوا سابقًا على الهامش إلى السوق."},{"type":"image","image":"1493809842364-78817add7ffb"},{"type":"heading","text":"ما الذي يجب التحقق منه قبل الالتزام"},{"type":"paragraph","text":"اسأل صراحة عمّا إذا كانت خطة دفعك ثابتة بالجنيه طوال مدتها أم خاضعة لإعادة تسعير، وإن كان كذلك، على أي أساس وبأي وتيرة. الخطة التي تبدو ميسورة اليوم قد تتحرك بشكل كبير إذا كانت مرتبطة بسعر يتغير قبل قسطك الأخير."},{"type":"paragraph","text":"لا شيء من هذا يعني تجنب السوق — بل يعني قراءة شروط العملة في عقدك المحدد بنفس العناية التي تقرأ بها تاريخ التسليم، لأن هذا البند يحدد بهدوء ما ستدفعه فعليًا في النهاية."}]'::jsonb,
      '2026-04-17T09:00:00.000Z',
      true),
  ('off-plan-worth-it-high-interest-rates',
      'Is Off-Plan Still Worth It in a High-Interest-Rate Environment?',
      'هل لا يزال الشراء على الخريطة يستحق العناء في ظل ارتفاع الفائدة؟',
      'With deposit and treasury certificate rates elevated, we ran the actual opportunity-cost math on a 4-year off-plan payment plan.',
      'مع ارتفاع معدلات الودائع وشهادات الادخار، أجرينا حساب تكلفة الفرصة البديلة الفعلي لخطة دفع على الخريطة لمدة 4 سنوات.',
      '1441986300917-64674bd600d8',
      'Karim Fahmy',
      '1463453091185-61582044d556',
      ARRAY['Off-plan', 'Investment', 'Financing']::text[],
      ARRAY['الشراء على الخريطة', 'استثمار', 'التمويل']::text[],
      '[{"type":"paragraph","text":"With bank deposit and treasury certificate rates at levels that make simply parking cash look attractive, it''s a fair question: does locking money into a 4-year off-plan payment plan still make sense?"},{"type":"heading","text":"The opportunity cost is real"},{"type":"paragraph","text":"When risk-free EGP returns are elevated, the bar for any other use of your capital gets higher too — including a payment plan on a property that won''t be ready for years. That''s a legitimate reason more buyers are asking harder questions before signing than they did a few years ago."},{"type":"heading","text":"What off-plan still offers that a deposit doesn''t"},{"type":"paragraph","text":"A high-yield certificate protects your cash; it doesn''t protect you from future construction cost inflation or from being priced out of a growth area once it''s built out. Off-plan pricing today typically still sits meaningfully below projected completion value in areas with genuine infrastructure momentum, which a cash return, however attractive, doesn''t replicate."},{"type":"image","image":"1441986300917-64674bd600d8"},{"type":"heading","text":"How to reconcile the two"},{"type":"paragraph","text":"This doesn''t have to be either-or: some clients keep the bulk of their capital earning the higher rate and commit only the required down payment and near-term installments to an off-plan unit, effectively riding both trades at once rather than going all-in on either. The math only works if the specific project''s appreciation potential genuinely outpaces what your capital is earning risk-free in the meantime — which is a project-by-project judgment, not a blanket rule."},{"type":"paragraph","text":"We don''t tell clients off-plan is automatically still the better trade in this rate environment — we walk through their specific numbers, because the honest answer depends on the project, the timeline, and what else their capital could be doing."}]'::jsonb,
      '[{"type":"paragraph","text":"مع معدلات الودائع البنكية وشهادات الادخار عند مستويات تجعل مجرد إيداع النقد يبدو جذابًا، السؤال المشروع هو: هل لا يزال حبس المال في خطة دفع لوحدة على الخريطة لمدة 4 سنوات منطقيًا؟"},{"type":"heading","text":"تكلفة الفرصة البديلة حقيقية"},{"type":"paragraph","text":"عندما ترتفع العوائد الخالية من المخاطر بالجنيه، يرتفع أيضًا السقف المطلوب لأي استخدام آخر لرأس مالك — بما في ذلك خطة دفع لعقار لن يكون جاهزًا لسنوات. هذا سبب مشروع لطرح المزيد من المشترين لأسئلة أكثر صرامة قبل التوقيع مقارنة بما كانوا يفعلونه قبل بضع سنوات."},{"type":"heading","text":"ما الذي لا يزال يقدمه الشراء على الخريطة ولا تقدمه الوديعة"},{"type":"paragraph","text":"الشهادة عالية العائد تحمي نقدك؛ لكنها لا تحميك من تضخم تكاليف البناء المستقبلية أو من استبعادك من منطقة نمو بعد اكتمالها. لا تزال أسعار الشراء على الخريطة اليوم أقل بكثير من القيمة المتوقعة عند الاكتمال في مناطق ذات زخم بنية تحتية حقيقي، وهو ما لا يكرره أي عائد نقدي مهما كان جذابًا."},{"type":"image","image":"1441986300917-64674bd600d8"},{"type":"heading","text":"كيف توفّق بين الاثنين"},{"type":"paragraph","text":"لا يجب أن يكون الأمر إما هذا أو ذاك: يحتفظ بعض عملائنا بمعظم رأس مالهم يحقق العائد الأعلى ويلتزمون فقط بالمقدم المطلوب والأقساط القريبة لوحدة على الخريطة، بحيث يركبون الصفقتين معًا بدلاً من المراهنة الكاملة على إحداهما. المعادلة تنجح فقط إذا كانت إمكانية نمو المشروع المحدد تتفوق فعليًا على ما يحققه رأس مالك خاليًا من المخاطر في الأثناء — وهذا حكم يخص كل مشروع على حدة، لا قاعدة عامة."},{"type":"paragraph","text":"لا نخبر عملاءنا أن الشراء على الخريطة هو تلقائيًا الصفقة الأفضل في بيئة الفائدة هذه — بل نستعرض معهم أرقامهم المحددة، لأن الإجابة الصادقة تعتمد على المشروع والجدول الزمني وما يمكن أن يحققه رأس مالهم في مكان آخر."}]'::jsonb,
      '2026-04-06T09:00:00.000Z',
      true),
  ('renting-vs-buying-cairo-numbers',
      'Renting vs. Buying in Cairo: A Real Numbers Comparison',
      'الإيجار أم الشراء في القاهرة: مقارنة بالأرقام الحقيقية',
      '''Rent is throwing money away'' is repeated constantly. Here''s the break-even math that actually determines who''s right.',
      '"الإيجار مجرد إهدار للمال" عبارة تتكرر باستمرار. إليك معادلة نقطة التعادل التي تحدد فعليًا من على حق.',
      '1600566753086-00f18fb6b3ea',
      'Sofia Marchetti',
      '1438761681033-6461ffad8d80',
      ARRAY['Home buying', 'Financing', 'Lifestyle']::text[],
      ARRAY['شراء المنزل', 'التمويل', 'أسلوب الحياة']::text[],
      '[{"type":"paragraph","text":"''Rent is throwing money away'' is one of the most repeated pieces of property advice in Cairo, and like most oversimplified advice, it''s only sometimes true."},{"type":"heading","text":"The break-even math"},{"type":"paragraph","text":"Comparing renting and buying honestly means weighing your monthly rent against the full cost of ownership — not just a mortgage or installment payment, but maintenance, compound fees, and the opportunity cost of the down payment you''d otherwise have invested elsewhere. In many established Cairo neighborhoods, rental yields in the 4-6% range mean the numbers are closer than either side of the debate likes to admit."},{"type":"heading","text":"What actually tips the decision"},{"type":"paragraph","text":"Time horizon matters more than almost any other factor: buying involves upfront transaction costs that only get diluted over several years of ownership, so a purchase you''ll hold two years rarely beats renting on pure economics, while a ten-year hold usually favors ownership even before accounting for appreciation."},{"type":"image","image":"1600566753086-00f18fb6b3ea"},{"type":"heading","text":"The non-financial side"},{"type":"paragraph","text":"Buying also locks in your housing cost against future rent increases and gives you control over renovations and long-term planning that renting doesn''t, both of which matter to different people to very different degrees — worth being honest with yourself about before running any spreadsheet."},{"type":"paragraph","text":"We''ve stopped giving clients a blanket answer on rent versus buy, because the right call depends on how long you''ll actually stay, not on which side of the debate sounds more responsible."}]'::jsonb,
      '[{"type":"paragraph","text":"\"الإيجار مجرد إهدار للمال\" واحدة من أكثر النصائح العقارية تكرارًا في القاهرة، ومثل معظم النصائح المبسطة، صحيحة أحيانًا فقط."},{"type":"heading","text":"معادلة نقطة التعادل"},{"type":"paragraph","text":"مقارنة الإيجار والشراء بصدق تعني موازنة إيجارك الشهري مقابل التكلفة الكاملة للتملك — ليس فقط القسط العقاري أو قسط التقسيط، بل الصيانة ورسوم الكمبوند وتكلفة الفرصة البديلة للمقدم الذي كان يمكن استثماره في مكان آخر. في كثير من أحياء القاهرة الراسخة، تعني عوائد الإيجار في نطاق 4-6% أن الأرقام أقرب مما يعترف به أي طرف في هذا الجدل."},{"type":"heading","text":"ما الذي يرجّح القرار فعليًا"},{"type":"paragraph","text":"الأفق الزمني أهم من أي عامل آخر تقريبًا: الشراء يتضمن تكاليف معاملات مقدمة لا تتلاشى إلا على مدى عدة سنوات من التملك، لذا فإن شراء ستحتفظ به لسنتين نادرًا ما يتفوق على الإيجار من الناحية الاقتصادية البحتة، بينما الاحتفاظ لعشر سنوات يفضّل عادة التملك حتى قبل احتساب نمو القيمة."},{"type":"image","image":"1600566753086-00f18fb6b3ea"},{"type":"heading","text":"الجانب غير المالي"},{"type":"paragraph","text":"يثبّت الشراء أيضًا تكلفة سكنك أمام ارتفاعات الإيجار المستقبلية ويمنحك السيطرة على التجديدات والتخطيط طويل المدى بما لا يتيحه الإيجار، وكلاهما يهم أشخاصًا مختلفين بدرجات متفاوتة جدًا — يستحق أن تكون صادقًا مع نفسك بشأنه قبل تشغيل أي جدول بيانات."},{"type":"paragraph","text":"توقفنا عن إعطاء عملائنا إجابة عامة عن الإيجار مقابل الشراء، لأن القرار الصحيح يعتمد على المدة التي ستبقاها فعليًا، لا على أي طرف في الجدل يبدو أكثر مسؤولية."}]'::jsonb,
      '2026-03-26T09:00:00.000Z',
      true),
  ('families-new-capital-home-priorities',
      'What Families Actually Look for in a New Capital Home',
      'ماذا تبحث العائلات فعليًا في منزل بالعاصمة الإدارية؟',
      'Not skylines and lagoons — floor plans, school proximity, and the compound amenities that actually get used.',
      'ليست خطوط الأفق والبحيرات الصناعية — بل المخططات الداخلية، وقرب المدارس، ومرافق الكمبوند التي تُستخدم فعليًا.',
      '1568605114967-8130f3a36994',
      'Amara Okafor',
      '1494790108377-be9c29b29330',
      ARRAY['Family', 'New Capital', 'Home buying']::text[],
      ARRAY['العائلة', 'العاصمة الإدارية الجديدة', 'شراء المنزل']::text[],
      '[{"type":"paragraph","text":"Marketing brochures sell New Capital on skylines and lagoons. The families we actually place there care about a much shorter, more practical list."},{"type":"heading","text":"Floor plans over floor-to-ceiling windows"},{"type":"paragraph","text":"Families consistently prioritize a genuinely separate kitchen and a layout that puts bedrooms away from the living area over dramatic glazing or a statement staircase — the features that photograph well aren''t always the ones that make daily life with kids easier."},{"type":"heading","text":"School proximity beats school reputation"},{"type":"paragraph","text":"A highly rated school 25 minutes away loses to a solid school 8 minutes away for most of the families we work with, once the daily reality of school-run traffic across a still-developing city sets in. We now recommend clients map schools relative to their exact building, not just the district."},{"type":"image","image":"1568605114967-8130f3a36994"},{"type":"heading","text":"Compound amenities that actually get used"},{"type":"paragraph","text":"A supervised kids'' pool and a genuinely secure, car-free internal walkway rank far above a rooftop lounge or a gym most parents won''t have time to use in the early years — amenities that reduce daily friction beat amenities that photograph well in the brochure."},{"type":"paragraph","text":"The families who end up happiest in New Capital are usually the ones who toured at 5pm on a weekday, not just on a quiet Friday morning showing — that''s when a compound''s real daily rhythm shows itself."}]'::jsonb,
      '[{"type":"paragraph","text":"تبيع الكتيبات التسويقية العاصمة الإدارية الجديدة بخطوط الأفق والبحيرات الصناعية. أما العائلات التي نضعها هناك فعليًا فتهتم بقائمة أقصر وأكثر عملية بكثير."},{"type":"heading","text":"المخطط الداخلي أهم من النوافذ الممتدة من الأرض للسقف"},{"type":"paragraph","text":"تعطي العائلات أولوية ثابتة لمطبخ منفصل فعليًا ولتصميم يبعد غرف النوم عن منطقة المعيشة أكثر من الزجاج الدرامي أو السلم المميز — الميزات التي تبدو جميلة في الصور ليست دائمًا التي تسهّل الحياة اليومية مع الأطفال."},{"type":"heading","text":"قرب المدرسة يتفوق على سمعتها"},{"type":"paragraph","text":"تخسر مدرسة مصنّفة عاليًا وتبعد 25 دقيقة أمام مدرسة جيدة تبعد 8 دقائق لدى معظم العائلات التي نتعامل معها، بمجرد أن يترسخ واقع حركة المرور اليومية لتوصيل الأطفال في مدينة لا تزال قيد التطوير. أصبحنا ننصح العملاء بتحديد المدارس بالنسبة لمبناهم بالضبط، لا الحي فقط."},{"type":"image","image":"1568605114967-8130f3a36994"},{"type":"heading","text":"مرافق الكمبوند التي تُستخدم فعليًا"},{"type":"paragraph","text":"حمام سباحة مخصص للأطفال بإشراف وممر داخلي آمن فعليًا وخالٍ من السيارات يتفوقان بكثير على صالة على السطح أو صالة رياضية لن يجد معظم الآباء وقتًا لاستخدامها في السنوات الأولى — المرافق التي تقلل الاحتكاك اليومي تتفوق على المرافق التي تبدو جميلة في الكتيب."},{"type":"paragraph","text":"العائلات التي تنتهي بها الحال الأكثر سعادة في العاصمة الإدارية هي عادة التي زارت الساعة 5 مساءً في يوم عمل، لا في جولة عرض هادئة صباح يوم جمعة فقط — فتلك هي اللحظة التي يظهر فيها الإيقاع اليومي الحقيقي للكمبوند."}]'::jsonb,
      '2026-03-15T09:00:00.000Z',
      true),
  ('downsizing-after-kids-move-out',
      'Downsizing After the Kids Move Out: A Practical Guide',
      'تصغير المسكن بعد استقلال الأبناء: دليل عملي',
      'Empty-nesters don''t just need a smaller home — they need one reassessed from scratch. Here''s how to do it without rushing.',
      'من استقل أبناؤهم لا يحتاجون فقط لمنزل أصغر — بل لإعادة تقييم كاملة من الصفر. إليك كيف تفعل ذلك دون تسرّع.',
      '1512917774080-9991f1c4c750',
      'Amara Okafor',
      '1494790108377-be9c29b29330',
      ARRAY['Home buying', 'Family', 'Lifestyle']::text[],
      ARRAY['شراء المنزل', 'العائلة', 'أسلوب الحياة']::text[],
      '[{"type":"paragraph","text":"The house that once felt exactly right for a family of five can start to feel oversized and expensive to maintain once the kids have moved out. Downsizing well is its own kind of decision, different from the moves that came before it."},{"type":"heading","text":"What to actually prioritize"},{"type":"paragraph","text":"Rather than simply buying a smaller version of the same home, empty-nesters are usually better served by reassessing from scratch: fewer bedrooms, but often more ground-floor living space, easier long-term accessibility, and lower ongoing maintenance rather than a strict size reduction for its own sake."},{"type":"heading","text":"The emotional side of the decision"},{"type":"paragraph","text":"Downsizing frequently gets delayed not for financial reasons but sentimental ones — the house holds twenty years of memories, and that''s a legitimate factor, not something to override with a spreadsheet. We find clients move more comfortably when they treat it as a deliberate choice made on their own timeline, not something rushed."},{"type":"image","image":"1512917774080-9991f1c4c750"},{"type":"heading","text":"The financial upside, done right"},{"type":"paragraph","text":"Selling a larger family home and moving into a smaller, well-located unit often releases significant equity that can fund retirement, support adult children, or simply reduce monthly outgoings meaningfully — but only if the new purchase is sized to actual future needs rather than driven by nostalgia for space you no longer use."},{"type":"paragraph","text":"The best downsizing decisions we''ve seen weren''t reactions to an empty house — they were planned a year or two ahead, giving the family time to choose well rather than move quickly."}]'::jsonb,
      '[{"type":"paragraph","text":"المنزل الذي كان يبدو مناسبًا تمامًا لعائلة من خمسة أفراد قد يبدأ يبدو كبيرًا جدًا ومكلفًا للصيانة بمجرد استقلال الأبناء. تصغير المسكن بشكل جيد قرار من نوع مختلف، يختلف عن الانتقالات التي سبقته."},{"type":"heading","text":"ما الذي يجب أن تعطيه الأولوية فعليًا"},{"type":"paragraph","text":"بدلاً من شراء نسخة أصغر ببساطة من نفس المنزل، عادة ما يكون من الأفضل لمن استقل أبناؤهم إعادة التقييم من الصفر: غرف نوم أقل، لكن غالبًا مساحة معيشة أكبر بالدور الأرضي، وسهولة وصول طويلة المدى، وصيانة مستمرة أقل بدلاً من تقليص المساحة كهدف بحد ذاته."},{"type":"heading","text":"الجانب العاطفي للقرار"},{"type":"paragraph","text":"غالبًا ما يتأخر تصغير المسكن ليس لأسباب مالية بل عاطفية — يحمل المنزل عشرين عامًا من الذكريات، وهذا عامل مشروع لا شيء يستدعي تجاوزه بجدول بيانات. نجد أن العملاء ينتقلون بارتياح أكبر عندما يتعاملون مع الأمر كقرار متعمد يتخذونه وفق جدولهم الزمني الخاص، لا شيئًا متسرعًا."},{"type":"image","image":"1512917774080-9991f1c4c750"},{"type":"heading","text":"الجانب المالي الإيجابي، إذا نُفِّذ بشكل صحيح"},{"type":"paragraph","text":"غالبًا ما يحرر بيع منزل عائلي كبير والانتقال إلى وحدة أصغر جيدة الموقع قيمة رأسمالية كبيرة يمكن أن تموّل التقاعد، أو تدعم الأبناء البالغين، أو ببساطة تقلل المصروفات الشهرية بشكل ملموس — لكن فقط إذا كان الشراء الجديد بحجم يناسب الاحتياجات المستقبلية الفعلية لا مدفوعًا بحنين لمساحة لم تعد تُستخدم."},{"type":"paragraph","text":"أفضل قرارات تصغير المسكن التي رأيناها لم تكن ردة فعل لمنزل فارغ — بل كانت مخططة قبل عام أو عامين، مما أعطى العائلة وقتًا للاختيار الجيد بدلاً من الانتقال السريع."}]'::jsonb,
      '2026-03-04T09:00:00.000Z',
      true),
  ('what-makes-developer-blue-chip',
      'What Makes a Developer "Blue Chip" in Egypt''s Market?',
      'ما الذي يجعل المطوّر "من الدرجة الأولى" في السوق المصري؟',
      'The term gets used loosely in every sales pitch. Here''s what our advisors actually check before trusting a developer''s brand.',
      'يُستخدم المصطلح بشكل فضفاض في كل عرض مبيعات. إليك ما يتحقق منه مستشارونا فعليًا قبل الوثوق بعلامة مطوّر.',
      '1545324418-cc1a3fa10c00',
      'Sofia Marchetti',
      '1438761681033-6461ffad8d80',
      ARRAY['Buying guide', 'Developer', 'Off-plan']::text[],
      ARRAY['دليل الشراء', 'المطوّر', 'الشراء على الخريطة']::text[],
      '[{"type":"paragraph","text":"''Blue chip developer'' gets used loosely in every sales pitch. The term should mean something specific, and it''s worth knowing what to actually check before you take it on faith."},{"type":"heading","text":"Delivery track record, not just project count"},{"type":"paragraph","text":"The number of projects a developer has announced tells you almost nothing; the number they''ve actually delivered on or close to schedule tells you nearly everything. Ask for specific handover dates on their last three completed projects and compare them against what was originally promised — the pattern matters more than any single project."},{"type":"heading","text":"Financial backing and how it''s structured"},{"type":"paragraph","text":"Developers backed by diversified balance sheets, bank financing lines, or listed parent companies are generally better positioned to weather a construction-cost spike or a sales slowdown without stalling a project midway, compared to smaller developers reliant almost entirely on ongoing sales revenue to fund construction."},{"type":"image","image":"1545324418-cc1a3fa10c00"},{"type":"heading","text":"How to actually vet one before reserving"},{"type":"paragraph","text":"Visit a previously delivered project in person rather than relying on renderings of the one you''re considering — finish quality and common-area maintenance on a completed development tell you more about a developer''s real standards than any brochure. Ask your broker directly whether they''d put their own money into this specific project, not just this developer''s brand in general."},{"type":"paragraph","text":"A strong brand name reduces risk, but it doesn''t eliminate the need to check the specific project — the best developers still have weaker projects, and it''s worth knowing the difference before you sign."}]'::jsonb,
      '[{"type":"paragraph","text":"تُستخدم عبارة \"مطوّر من الدرجة الأولى\" بشكل فضفاض في كل عرض مبيعات. يجب أن يعني المصطلح شيئًا محددًا، ويستحق الأمر معرفة ما يجب التحقق منه فعليًا قبل تصديقه دون تحقق."},{"type":"heading","text":"سجل التسليم، لا مجرد عدد المشاريع"},{"type":"paragraph","text":"عدد المشاريع التي أعلن عنها المطوّر لا يخبرك بشيء تقريبًا؛ عدد المشاريع التي سلّمها فعليًا في الموعد أو قريبًا منه يخبرك بكل شيء تقريبًا. اطلب تواريخ تسليم محددة لآخر ثلاثة مشاريع أنجزها وقارنها بما وُعد به في البداية — النمط أهم من أي مشروع منفرد."},{"type":"heading","text":"الدعم المالي وكيفية هيكلته"},{"type":"paragraph","text":"المطورون المدعومون بميزانيات عمومية متنوعة، أو خطوط تمويل بنكية، أو شركات أم مدرجة عادة ما يكونون في وضع أفضل لتحمل ارتفاع تكاليف البناء أو تباطؤ المبيعات دون توقف المشروع في منتصفه، مقارنة بالمطورين الأصغر المعتمدين بشكل شبه كامل على إيرادات المبيعات المستمرة لتمويل البناء."},{"type":"image","image":"1545324418-cc1a3fa10c00"},{"type":"heading","text":"كيف تتحقق فعليًا قبل الحجز"},{"type":"paragraph","text":"قم بزيارة مشروع سابق تم تسليمه شخصيًا بدلاً من الاعتماد على تصورات المشروع الذي تفكر فيه — جودة التشطيب وصيانة المناطق المشتركة في مشروع مكتمل تخبرك عن معايير المطوّر الحقيقية أكثر من أي كتيب. اسأل سمسارك مباشرة عمّا إذا كان سيضع ماله الخاص في هذا المشروع تحديدًا، لا فقط في اسم علامة هذا المطوّر بشكل عام."},{"type":"paragraph","text":"اسم العلامة القوي يقلل المخاطر، لكنه لا يلغي الحاجة للتحقق من المشروع المحدد — فحتى أفضل المطورين لديهم مشاريع أضعف، ويستحق الأمر معرفة الفرق قبل التوقيع."}]'::jsonb,
      '2026-02-21T09:00:00.000Z',
      true),
  ('amenities-arms-race-compounds',
      'Inside the Amenities Arms Race: Clubhouses, Lagoons and What They Really Cost You',
      'سباق التسهيلات: النوادي والبحيرات الصناعية وتكلفتها الحقيقية عليك',
      'How amenity-heavy compounds price shared facilities into your unit cost — and the recurring service charge that outlasts the marketing.',
      'كيف تُسعِّر الكمبوندات الغنية بالمرافق التسهيلات المشتركة ضمن تكلفة وحدتك — ورسوم الخدمة المستمرة التي تدوم أطول من التسويق.',
      '1564013799919-ab600027ffc6',
      'Sofia Marchetti',
      '1438761681033-6461ffad8d80',
      ARRAY['Buying guide', 'Lifestyle', 'Off-plan']::text[],
      ARRAY['دليل الشراء', 'أسلوب الحياة', 'الشراء على الخريطة']::text[],
      '[{"type":"paragraph","text":"Every new compound launch seems to top the last one: bigger lagoons, more clubhouses, longer amenity lists. None of it is free, and almost none of it is separately priced — it''s baked into your per-meter rate."},{"type":"heading","text":"How shared amenities get priced into your unit"},{"type":"paragraph","text":"A crystal lagoon or an extensive clubhouse adds real construction and ongoing maintenance cost, and developers recover that through the per-meter sale price across every unit in the project, whether or not you personally use the amenity. That''s worth knowing before comparing two projects purely on price per meter."},{"type":"heading","text":"The ongoing cost that outlasts the marketing"},{"type":"paragraph","text":"Amenity-heavy compounds also carry higher recurring service charges, since someone has to maintain that lagoon, staff that clubhouse, and landscape those grounds indefinitely — a cost that continues long after the launch excitement fades, and one buyers frequently underweight when comparing options."},{"type":"image","image":"1564013799919-ab600027ffc6"},{"type":"heading","text":"What actually holds value"},{"type":"paragraph","text":"The amenities that tend to hold resale value over time are the ones with genuine ongoing utility — security, green space, and functioning basic services — more consistently than the most photogenic single feature, which can start to look dated once the next development one compound over launches something newer."},{"type":"paragraph","text":"We encourage clients to ask for the current service charge on a comparable, already-operating phase, not just the projected one in the brochure — that number tells you what you''re actually signing up to pay every year, not just once."}]'::jsonb,
      '[{"type":"paragraph","text":"يبدو أن كل إطلاق كمبوند جديد يتفوق على سابقه: بحيرات صناعية أكبر، نوادٍ أكثر، قوائم مرافق أطول. لا شيء من هذا مجاني، وتقريبًا لا شيء منه يُسعَّر بشكل منفصل — بل يُدمج في سعر المتر لديك."},{"type":"heading","text":"كيف تُسعَّر المرافق المشتركة ضمن وحدتك"},{"type":"paragraph","text":"تضيف البحيرة الصناعية أو النادي الواسع تكلفة بناء وصيانة مستمرة حقيقية، ويسترد المطورون هذه التكلفة عبر سعر المتر عبر كل وحدة في المشروع، سواء استخدمت هذا المرفق شخصيًا أم لا. هذا يستحق معرفته قبل مقارنة مشروعين بناءً على سعر المتر فقط."},{"type":"heading","text":"التكلفة المستمرة التي تدوم أطول من التسويق"},{"type":"paragraph","text":"تحمل الكمبوندات الغنية بالمرافق أيضًا رسوم خدمة دورية أعلى، لأن أحدًا ما يجب أن يصون تلك البحيرة، ويوظّف طاقمًا لذلك النادي، وينسّق تلك المساحات الخضراء إلى أجل غير مسمى — تكلفة تستمر طويلاً بعد أن يخفت حماس الإطلاق، وهي تكلفة يقلل المشترون من وزنها غالبًا عند مقارنة الخيارات."},{"type":"image","image":"1564013799919-ab600027ffc6"},{"type":"heading","text":"ما الذي يحافظ على قيمته فعليًا"},{"type":"paragraph","text":"المرافق التي تميل للحفاظ على قيمة إعادة البيع بمرور الوقت هي تلك ذات المنفعة المستمرة الحقيقية — الأمن، والمساحات الخضراء، والخدمات الأساسية العاملة — بشكل أكثر ثباتًا من الميزة الواحدة الأكثر جاذبية بصريًا، التي قد تبدأ تبدو قديمة بمجرد أن يطلق كمبوند مجاور شيئًا أحدث."},{"type":"paragraph","text":"نشجع عملاءنا على السؤال عن رسوم الخدمة الحالية في مرحلة مماثلة تعمل بالفعل، لا الرسوم المتوقعة في الكتيب فقط — هذا الرقم يخبرك بما ستلتزم بدفعه فعليًا كل عام، لا مرة واحدة فقط."}]'::jsonb,
      '2026-02-10T09:00:00.000Z',
      true),
  ('property-registration-process-egypt',
      'The Property Registration Process in Egypt, Step by Step',
      'خطوات تسجيل الملكية العقارية في مصر خطوة بخطوة',
      'A signed contract isn''t legal ownership. Here''s what tabo registration actually involves, and where the delays tend to happen.',
      'العقد الموقّع ليس هو الملكية القانونية. إليك ما يتضمنه تسجيل التابو فعليًا، وأين تحدث التأخيرات عادة.',
      '1600210492486-724fe5c67fb0',
      'Yasmin El-Sayed',
      '1517841905240-472988babdf9',
      ARRAY['Legal', 'Buying guide']::text[],
      ARRAY['قانوني', 'دليل الشراء']::text[],
      '[{"type":"paragraph","text":"A signed contract isn''t the same as legal ownership. Registration — getting the property into your name at the official registry — is the step that actually protects you, and it''s also the step most buyers understand the least."},{"type":"heading","text":"Why registration matters more than people think"},{"type":"paragraph","text":"Without registration, your claim to the property rests on a contract, which is enforceable but far weaker than a registered title (known as a ''tabo'') if a dispute or a competing claim ever arises. Many buyers in Egypt historically skipped or delayed registration due to cost and paperwork, leaving properties technically unregistered for years — a risk that''s increasingly worth avoiding as enforcement and awareness have both increased."},{"type":"heading","text":"The typical steps"},{"type":"paragraph","text":"The process generally moves through notarizing the sale contract, verifying the property is free of liens or disputes at the relevant survey authority, paying the applicable registration fees and any outstanding property tax, and finally recording the transfer at the real estate registry office covering that property''s location."},{"type":"image","image":"1600210492486-724fe5c67fb0"},{"type":"heading","text":"Realistic timelines and where delays happen"},{"type":"paragraph","text":"A straightforward, undisputed registration can move in a matter of weeks; most of the delays we see stem from incomplete developer paperwork on newer off-plan units, or from a chain of previous unregistered transfers that need to be resolved before your own registration can proceed. Ask your developer directly, before you buy, whether the specific unit''s registration paperwork is fully in order."},{"type":"paragraph","text":"Registration fees feel like an avoidable cost when the contract already feels binding — but it''s the one step that converts ''I have an agreement'' into ''I legally own this,'' and that difference matters most exactly when you''d least want it to."}]'::jsonb,
      '[{"type":"paragraph","text":"العقد الموقّع ليس هو نفسه الملكية القانونية. التسجيل — نقل العقار إلى اسمك في السجل الرسمي — هو الخطوة التي تحميك فعليًا، وهي أيضًا الخطوة التي يفهمها معظم المشترين بأقل قدر."},{"type":"heading","text":"لماذا يهم التسجيل أكثر مما يظن الناس"},{"type":"paragraph","text":"بدون تسجيل، تستند مطالبتك بالعقار إلى عقد، وهو قابل للتنفيذ لكنه أضعف بكثير من سند ملكية مسجل (يُعرف بـ\"التابو\") إذا نشأ نزاع أو مطالبة منافسة. تخطى كثير من المشترين في مصر تاريخيًا التسجيل أو أخّروه بسبب التكلفة والإجراءات، تاركين عقارات غير مسجلة فعليًا لسنوات — وهو خطر يستحق تجنبه بشكل متزايد مع ازدياد التنفيذ والوعي معًا."},{"type":"heading","text":"الخطوات المعتادة"},{"type":"paragraph","text":"تمر العملية عادة بتوثيق عقد البيع، والتحقق من خلو العقار من أي رهون أو نزاعات لدى جهة المساحة المختصة، ودفع رسوم التسجيل المستحقة وأي ضريبة عقارية متأخرة، وأخيرًا تسجيل نقل الملكية في مكتب الشهر العقاري المختص بموقع العقار."},{"type":"image","image":"1600210492486-724fe5c67fb0"},{"type":"heading","text":"جداول زمنية واقعية وأين تحدث التأخيرات"},{"type":"paragraph","text":"يمكن أن يتم التسجيل المباشر غير المتنازع عليه في غضون أسابيع؛ معظم التأخيرات التي نراها تنشأ من أوراق مطوّر غير مكتملة لوحدات جديدة على الخريطة، أو من سلسلة تنازلات سابقة غير مسجلة يجب حلها قبل أن يتقدم تسجيلك الخاص. اسأل مطوّرك مباشرة، قبل الشراء، عمّا إذا كانت أوراق تسجيل الوحدة المحددة مكتملة تمامًا."},{"type":"paragraph","text":"تبدو رسوم التسجيل تكلفة يمكن تجنبها عندما يبدو العقد ملزمًا بالفعل — لكنها الخطوة الوحيدة التي تحوّل \"لدي اتفاق\" إلى \"أملك هذا قانونًا\"، وهذا الفارق يهم أكثر ما يكون بالضبط عندما تكون أقل رغبة في احتياجه."}]'::jsonb,
      '2026-01-30T09:00:00.000Z',
      true),
  ('buying-property-non-resident-egyptian',
      'Buying Property in Egypt as a Non-Resident Egyptian',
      'شراء عقار في مصر للمصريين المقيمين بالخارج',
      'Power of attorney, currency transfer rules, and what to get right before you buy a home back home from abroad.',
      'التوكيل، وقواعد تحويل العملة، وما يجب ترتيبه بشكل صحيح قبل شراء منزل في الوطن وأنت في الخارج.',
      '1613490493576-7fde63acd811',
      'Yasmin El-Sayed',
      '1517841905240-472988babdf9',
      ARRAY['Legal', 'Buying guide', 'Financing']::text[],
      ARRAY['قانوني', 'دليل الشراء', 'التمويل']::text[],
      '[{"type":"paragraph","text":"Buying a home back in Egypt while living abroad is one of the most common requests we get — and one of the most frequently mishandled, mostly because it''s attempted entirely by email and phone without the right paperwork in place."},{"type":"heading","text":"Buying without being physically present"},{"type":"paragraph","text":"A properly drafted power of attorney, notarized at the Egyptian consulate in your country of residence, lets a trusted representative sign contracts, make payments, and eventually complete registration on your behalf. The scope of that power of attorney matters enormously — a narrowly worded one can leave your representative unable to act on something as simple as a payment plan amendment."},{"type":"heading","text":"Moving money across the border"},{"type":"paragraph","text":"Transfers from abroad for property purchases generally need to move through proper banking channels to be recognized and to qualify for any incentive programs aimed at non-resident buyers, rather than informal transfer methods that can complicate both the purchase and any future resale."},{"type":"image","image":"1613490493576-7fde63acd811"},{"type":"heading","text":"What we tell every non-resident client"},{"type":"paragraph","text":"Work with a lawyer who specializes specifically in non-resident transactions, not just general property law, since the power-of-attorney and currency-transfer details are where the process most commonly goes wrong. And where possible, plan at least one in-person visit around key milestones — the reservation and the final registration — even if a representative handles everything in between."},{"type":"paragraph","text":"Distance shouldn''t be the reason a purchase goes wrong — with the right paperwork set up before you commit a deposit, buying from abroad can be nearly as smooth as buying in person."}]'::jsonb,
      '[{"type":"paragraph","text":"شراء منزل في مصر أثناء الإقامة في الخارج من أكثر الطلبات شيوعًا التي نتلقاها — وأيضًا من أكثرها تعرضًا لسوء الإدارة، غالبًا لأنه يُنفَّذ بالكامل عبر البريد الإلكتروني والهاتف دون الأوراق الصحيحة في مكانها."},{"type":"heading","text":"الشراء دون التواجد الجسدي"},{"type":"paragraph","text":"توكيل رسمي مُعد بشكل صحيح، وموثّق في القنصلية المصرية في بلد إقامتك، يتيح لممثل موثوق توقيع العقود، وسداد الدفعات، وإتمام التسجيل نيابة عنك في النهاية. نطاق هذا التوكيل مهم للغاية — توكيل بصياغة ضيقة قد يترك ممثلك عاجزًا عن التصرف في أمر بسيط مثل تعديل خطة دفع."},{"type":"heading","text":"نقل الأموال عبر الحدود"},{"type":"paragraph","text":"يجب أن تمر التحويلات من الخارج لشراء العقارات عمومًا عبر القنوات المصرفية الرسمية لتكون معترفًا بها ولتستوفي شروط أي برامج حوافز موجهة للمشترين غير المقيمين، بدلاً من طرق تحويل غير رسمية قد تعقّد كلاً من الشراء وأي إعادة بيع مستقبلية."},{"type":"image","image":"1613490493576-7fde63acd811"},{"type":"heading","text":"ما الذي نخبر به كل عميل غير مقيم"},{"type":"paragraph","text":"اعمل مع محامٍ متخصص تحديدًا في معاملات غير المقيمين، لا في قانون العقارات العام فقط، لأن تفاصيل التوكيل ونقل العملة هي غالبًا حيث تسوء العملية أكثر ما تسوء. وحيثما أمكن، خطط لزيارة شخصية واحدة على الأقل حول المحطات الرئيسية — الحجز والتسجيل النهائي — حتى لو تولى ممثل كل ما بينهما."},{"type":"paragraph","text":"لا ينبغي أن تكون المسافة سبب فشل صفقة الشراء — فمع الأوراق الصحيحة قبل الالتزام بدفعة، يمكن أن يكون الشراء من الخارج سلسًا تقريبًا مثل الشراء الشخصي."}]'::jsonb,
      '2026-01-19T09:00:00.000Z',
      true),
  ('quarterly-market-snapshot-greater-cairo',
      'Quarterly Market Snapshot: Where Prices Are Moving Across Greater Cairo',
      'لمحة السوق الفصلية: أين تتحرك الأسعار في القاهرة الكبرى',
      'Our first quarterly read on price-per-meter movement across Greater Cairo''s key districts — based on transaction data, not marketing.',
      'لمحتنا الفصلية الأولى عن حركة سعر المتر عبر أهم أحياء القاهرة الكبرى — بناءً على بيانات المعاملات لا التسويق.',
      '1600596542815-ffad4c1539a9',
      'Daniel Brooks',
      '1500648767791-00dcc994a43e',
      ARRAY['Market insight', 'Quarterly snapshot']::text[],
      ARRAY['رؤى السوق', 'لمحة فصلية']::text[],
      '[{"type":"paragraph","text":"Our first quarterly snapshot looks at where price-per-meter has actually moved across Greater Cairo''s key districts over the past quarter — not where the marketing says it''s headed, but what transaction data shows."},{"type":"heading","text":"The steady performers"},{"type":"paragraph","text":"5th Settlement and Sheikh Zayed both posted modest, low-single-digit quarter-on-quarter gains, consistent with their status as mature, low-volatility markets where supply and demand are relatively balanced and buyers are largely end-users rather than speculators."},{"type":"heading","text":"The fast movers"},{"type":"paragraph","text":"New Capital and Al Shrouk saw the sharpest percentage gains this quarter, driven respectively by continued infrastructure delivery news and a wave of new buyers discovering Al Shrouk''s value gap relative to its neighbors — both patterns worth watching rather than chasing on a single quarter''s data."},{"type":"image","image":"1600596542815-ffad4c1539a9"},{"type":"heading","text":"What we''re watching next quarter"},{"type":"paragraph","text":"Ras El Hekma pricing remains too early-stage for a meaningful quarter-on-quarter read, but we expect that to change quickly as more phases launch. We''re also watching whether North Coast pricing broadly holds through the off-season, which has historically been a better indicator of underlying demand than in-season activity."},{"type":"paragraph","text":"This is the first entry in what we intend to make a regular series — the goal is to give clients a grounded, numbers-first view of the market instead of the latest headline-driven narrative."}]'::jsonb,
      '[{"type":"paragraph","text":"تنظر لمحتنا الفصلية الأولى إلى أين تحرك سعر المتر فعليًا عبر الأحياء الرئيسية في القاهرة الكبرى خلال الربع الماضي — لا إلى أين يقول التسويق إنه متجه، بل إلى ما تُظهره بيانات المعاملات الفعلية."},{"type":"heading","text":"الأداء الثابت"},{"type":"paragraph","text":"سجّل كل من التجمع الخامس والشيخ زايد مكاسب متواضعة بخانة آحاد منخفضة على أساس ربع سنوي، بما يتسق مع مكانتهما كأسواق ناضجة ومنخفضة التقلب حيث العرض والطلب متوازنان نسبيًا والمشترون في معظمهم مستخدمون نهائيون لا مضاربون."},{"type":"heading","text":"الأسرع حركة"},{"type":"paragraph","text":"شهدت العاصمة الإدارية الجديدة والشروق أكبر المكاسب النسبية هذا الربع، مدفوعة على التوالي بأخبار استمرار تسليم البنية التحتية وموجة من المشترين الجدد الذين يكتشفون فجوة القيمة في الشروق مقارنة بجيرانها — نمطان يستحقان المراقبة لا المطاردة بناءً على بيانات ربع واحد."},{"type":"image","image":"1600596542815-ffad4c1539a9"},{"type":"heading","text":"ما الذي نراقبه في الربع القادم"},{"type":"paragraph","text":"لا تزال أسعار رأس الحكمة في مرحلة مبكرة جدًا لقراءة ربع سنوية ذات معنى، لكننا نتوقع أن يتغير ذلك بسرعة مع إطلاق المزيد من المراحل. نراقب أيضًا ما إذا كانت أسعار الساحل الشمالي ستصمد بشكل عام خلال الموسم المنخفض، وهو ما كان تاريخيًا مؤشرًا أفضل على الطلب الفعلي من نشاط الموسم."},{"type":"paragraph","text":"هذه هي أول لمحة في سلسلة ننوي جعلها منتظمة — الهدف هو تزويد عملائنا برؤية قائمة على الأرقام والواقع بدلاً من أحدث سردية تقودها العناوين."}]'::jsonb,
      '2026-01-08T09:00:00.000Z',
      true)
